function calculateMediaReliability(inputs) {
  const { journalisticIntegrity, sourceTransparency, biasIndicators, evidenceQuality, platformReputation, headlineAccuracy } = inputs;

  // Validate inputs: Ensure all are numbers and within the 1-10 range
  const validate = (value) => {
    const num = parseFloat(value);
    if (isNaN(num) || num < 1 || num > 10) {
      throw new Error(`Invalid input: All scores must be between 1 and 10. Received '${value}'`);
    }
    return num;
  };

  try {
    const jI = validate(journalisticIntegrity);
    const sT = validate(sourceTransparency);
    const bI = validate(biasIndicators);
    const eQ = validate(evidenceQuality);
    const pR = validate(platformReputation);
    const hA = validate(headlineAccuracy);

    // Define weights for each criterion
    const weights = {
      journalisticIntegrity: 0.25,
      sourceTransparency: 0.20,
      biasIndicators: 0.20,
      evidenceQuality: 0.15,
      platformReputation: 0.10,
      headlineAccuracy: 0.10
    };

    // Calculate the raw weighted score
    const rawScore = (
      (jI * weights.journalisticIntegrity) +
      (sT * weights.sourceTransparency) +
      (bI * weights.biasIndicators) +
      (eQ * weights.evidenceQuality) +
      (pR * weights.platformReputation) +
      (hA * weights.headlineAccuracy)
    );

    // Normalize the score to a 0-100% scale
    // Max possible raw score is 10 * (sum of weights) = 10 * 1 = 10
    let reliabilityScore = (rawScore / 10) * 100;

    // Cap the score between 0 and 100
    reliabilityScore = Math.max(0, Math.min(100, reliabilityScore));

    let trustLevel = '';
    let recommendation = '';

    if (reliabilityScore >= 90) {
      trustLevel = 'Very High';
      recommendation = 'This source demonstrates exceptional reliability and adherence to journalistic standards. Highly recommended.';
    } else if (reliabilityScore >= 75) {
      trustLevel = 'High';
      recommendation = 'Generally reliable with strong journalistic practices. Exercise standard critical thinking, but information is likely credible.';
    } else if (reliabilityScore >= 60) {
      trustLevel = 'Moderate';
      recommendation = 'May contain some biases or occasional inaccuracies. Cross-reference with other sources, especially on contentious topics.';
    } else if (reliabilityScore >= 40) {
      trustLevel = 'Low';
      recommendation = 'Significant concerns regarding reliability, bias, or factual accuracy. Verify all information extensively with multiple independent sources.';
    } else {
      trustLevel = 'Very Low';
      recommendation = 'Highly unreliable. This source likely disseminates misinformation or propaganda. Avoid using as a primary source of information.';
    }

    return {
      reliabilityScore: reliabilityScore,
      trustLevel: trustLevel,
      recommendation: recommendation
    };
  } catch (error) {
    // Handle invalid input errors gracefully, e.g., return default values or error messages
    return {
      reliabilityScore: NaN,
      trustLevel: 'Error',
      recommendation: error.message || 'Please ensure all inputs are valid numbers between 1 and 10.'
    };
  }
}
